# -*- coding: utf-8 -*-
"""Dinshunoslik - 8 mavzu konspekt generatori."""
import zipfile, datetime
TOPICS = []
def esc(t): return t.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace('"',"&quot;")
def run(text,bold=False,size=28,font="Times New Roman"):
    rpr='<w:rPr><w:rFonts w:ascii="%s" w:hAnsi="%s" w:cs="%s"/>'%(font,font,font)
    if bold: rpr+='<w:b/><w:bCs/>'
    rpr+='<w:sz w:val="%d"/><w:szCs w:val="%d"/></w:rPr>'%(size,size)
    return '<w:r>%s<w:t xml:space="preserve">%s</w:t></w:r>'%(rpr,esc(text))
def para(text,bold=False,size=28,align="both",indent_first=709,space_after=120,line=360,keep_next=False):
    ppr='<w:pPr>'
    if keep_next: ppr+='<w:keepNext/>'
    ppr+='<w:spacing w:after="%d" w:line="%d" w:lineRule="auto"/>'%(space_after,line)
    if indent_first: ppr+='<w:ind w:firstLine="%d"/>'%indent_first
    ppr+='<w:jc w:val="%s"/></w:pPr>'%align
    return '<w:p>%s%s</w:p>'%(ppr,run(text,bold=bold,size=size))
def page_break(): return '<w:p><w:r><w:br w:type="page"/></w:r></w:p>'
def empty_para(): return '<w:p><w:pPr><w:spacing w:after="0" w:line="360" w:lineRule="auto"/></w:pPr></w:p>'
def build_topic(t,is_first):
    parts=[]
    if not is_first: parts.append(page_break())
    parts.append(para("%d-MAVZU. %s"%(t["num"],t["title"].upper()),bold=True,size=30,align="center",indent_first=0,space_after=180,keep_next=True))
    parts.append(para("Reja:",bold=True,size=28,align="left",indent_first=0,space_after=60,keep_next=True))
    for i,r in enumerate(t["reja"],1): parts.append(para("%d. %s"%(i,r),size=28,align="left",indent_first=360,space_after=40))
    parts.append(empty_para())
    for idx,(head,paras) in enumerate(t["sections"],1):
        parts.append(para("%d. %s"%(idx,head),bold=True,size=28,align="left",indent_first=0,space_after=80,keep_next=True))
        for p in paras: parts.append(para(p,size=28,align="both",indent_first=709,space_after=120))
    return "".join(parts)
def build_document():
    body="".join(build_topic(t,i==0) for i,t in enumerate(TOPICS))
    sect='<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/><w:pgNumType w:start="1"/></w:sectPr>'
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>'+body+sect+'</w:body></w:document>'
CT='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'
RE='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'
DR='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>'
ST='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/><w:lang w:val="uz-Latn-UZ"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="360" w:lineRule="auto"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>'
def cp():
    n=datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Dinshunoslik</dc:title><dc:creator>Konspekt</dc:creator><dcterms:created xsi:type="dcterms:W3CDTF">%s</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">%s</dcterms:modified></cp:coreProperties>'%(n,n)
AP='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties"><Application>Konspekt</Application></Properties>'
def write_docx(path):
    with zipfile.ZipFile(path,"w",zipfile.ZIP_DEFLATED) as z:
        z.writestr("[Content_Types].xml",CT); z.writestr("_rels/.rels",RE)
        z.writestr("word/document.xml",build_document()); z.writestr("word/_rels/document.xml.rels",DR)
        z.writestr("word/styles.xml",ST); z.writestr("docProps/core.xml",cp()); z.writestr("docProps/app.xml",AP)
    print("OK:",path,"|",len(TOPICS),"mavzu")

TOPICS.append({"num":1,"title":"Islom dini, tushunchalari va ta'limoti","reja":["Islom dinining paydo bo'lishi va tarixi.","Islomning asosiy manbalari: Qur'on va Sunnat.","Islomning besh ustuni (arkonu islom).","Islomning olamga tarqalishi va O'zbekistondagi o'rni."],"sections":[("Islom dinining paydo bo'lishi va tarixi",["Islom dini VII asrning boshida Arabiston yarim orolida, Muhammad payg'ambar (s.a.v.) tomonidan targ'ib qilingan. Payg'ambarimiz 570-yilda Makkada tug'ilgan, 610-yili (40 yoshida) Hiro g'orida birinchi vahiy olgan va shu paytdan boshlab 23 yil davomida islom da'vatini olib borgan.","Hijrat — 622-yili Muhammad payg'ambar va sahobalarning Makkadan Madinaga ko'chishi, islom tarixining muhim voqealaridan biridir. Hijriy taqvim aynan shu sanadan boshlanadi. Madinada birinchi islom davlati va jamiyati shakllantirildi.","632-yili Muhammad payg'ambar vafotidan so'ng 'rashidiy xalifalar' davri boshlandi: Abu Bakr, Umar, Usmon, Ali. Keyinchalik Umaviylar, Abbosiylar va boshqa sulolalar islom davlatini boshqarib, dinning butun dunyo bo'ylab tarqalishiga hissa qo'shdilar."]),("Islomning asosiy manbalari: Qur'on va Sunnat",["Qur'oni Karim — Allohning Muhammad payg'ambarga vahiy orqali yuborilgan kalomi, islomning birinchi va asosiy manbasidir. U 114 suradan iborat, har bir sura oyatlardan tarkib topgan. Qur'on arab tilida nozil bo'lgan va musulmonlar uchun muqaddas kitobdir.","Qur'on inson hayotining barcha jihatlari — e'tiqod, ibodat, axloq, oila, ijtimoiy munosabatlar, iqtisodiyot, davlat boshqaruvi haqida ko'rsatma beradi. U musulmonlarni adolat, mehr-shafqat, halollik, sabr-toqat va o'zaro hurmatga chaqiradi.","Sunnat — Muhammad payg'ambarning so'zlari, ishlari va tasdiqlari majmuasi bo'lib, Qur'ondan keyingi ikkinchi muhim manbadir. Hadislar — bu Sunnat haqidagi rivoyatlar. Eng nufuzli hadis to'plamlari: Sahihul Buxoriy (Imom al-Buxoriy), Sahihul Muslim, Sunan at-Termiziy, Abu Dovud va boshqalar."]),("Islomning besh ustuni (arkonu islom)",["Islomning birinchi ustuni — shahodat (kalimai shahodat): 'Ashhadu an la ilaha illalloh va ashhadu anna Muhammadan rasulullah' — 'Allohdan boshqa iloh yo'qligiga va Muhammad uning rasuli ekanligiga shohidlik beraman'. Bu kalima musulmonlikning asosiy e'tirofidir.","Ikkinchi ustun — namoz: kuniga besh marta o'qiladigan ibodat (bomdod, peshin, asr, shom, xufton). Uchinchi ustun — zakot: nisob hajmiga yetgan mulkdan kambag'allarga beriladigan moliyaviy ibodat (odatda 2,5 foiz). U ijtimoiy adolatni ta'minlovchi vositadir.","To'rtinchi ustun — Ramazon oyida ro'za tutish: ushbu oyda quyosh chiqishidan botishigacha tom ma'noda ovqat va suvdan tiyilish hamda har xil yomon harakatlardan saqlanish. Beshinchi ustun — haj: imkoni bo'lgan har bir musulmonning umrida bir marta Makkaga muqaddas safarni amalga oshirishi."]),("Islomning olamga tarqalishi va O'zbekistondagi o'rni",["Islom dini qisqa vaqt ichida Arabiston, Yaqin Sharq, Shimoliy Afrika, Markaziy Osiyo va Hindistonga tarqaldi. Hozirda dunyoda 1,9 milliarddan ortiq musulmonlar bor — bu jahon aholisining qariyb 25 foizini tashkil etadi. Islom — dunyodagi ikkinchi yirik din.","O'rta Osiyoga islom VII-VIII asrlarda kirib kelgan. Imom al-Buxoriy, Imom at-Termiziy, Burhoniddin al-Marg'inoniy, Bahouddin Naqshband, Ahmad Yassaviy kabi buyuk allomalar yer yuzimizdan chiqib, butun islom olamiga ma'lum bo'lgan asarlar yaratdilar. Buxoro va Samarqand islom ilm-fanining markazlariga aylangan.","Bugungi O'zbekistonda 90 foizdan ortiq aholi musulmonlardir. Davlat dunyoviy bo'lsa-da, islom qadriyatlarini hurmat qiladi va diniy bag'rikenglikni qo'llab-quvvatlaydi. Toshkent, Samarqand, Buxoroda muqaddas joylar va islom universitetlari faoliyat yuritmoqda. Imom al-Buxoriy nomidagi xalqaro tadqiqot markazi ham mamlakatda mavjud."])],})

TOPICS.append({"num":2,"title":"Nasroniylik (Xristianlik) va Yahudiylik dinlari","reja":["Yahudiylik dinining paydo bo'lishi va xususiyatlari.","Nasroniylik (Xristianlik) dinining shakllanishi.","Xristianlikning asosiy yo'nalishlari.","Yahudiylik va xristianlikning dunyodagi o'rni."],"sections":[("Yahudiylik dinining paydo bo'lishi va xususiyatlari",["Yahudiylik (iudaizm) — eng qadimgi monoteistik dinlardan biri bo'lib, eramizdan avvalgi II ming yillikda Yaqin Sharqda paydo bo'lgan. Uning asoschisi Ibrohim payg'ambar (Avraam) hisoblanadi. Yahudiylar Allohni Yahve deb atashadi va o'zlarini u tomonidan tanlangan xalq deb hisoblaydilar.","Yahudiylikning muqaddas kitobi — Tanax (xristian an'anasida 'Eski Ahd'). U uch qismdan iborat: Tavrot (Musoga nozil bo'lgan beshta kitob), Neviim (payg'ambarlar) va Ketuvim (yozuvlar). Talmud — bu yahudiy ulamolarining sharhlari va huquqiy qoidalar to'plami.","Yahudiylikning asosiy aqidalari: Yahveni yagona iloh deb tan olish, 10 ta amrga rioya qilish (Sinay tog'ida Musoga berilgan), shanbada (shabbat) dam olish va ibodat qilish, oilaviy va ovqatlanish qoidalari (kashrut), masihni kutish. Hozirda dunyoda 14-15 million yahudiy bor."]),("Nasroniylik (Xristianlik) dinining shakllanishi",["Xristianlik milodning I asrida Falastinda paydo bo'lgan. Asoschisi Iso payg'ambar (Iisus Xristos) hisoblanadi. Iso 4-yil atrofida Vifleemda tug'ilgan, 30 yoshida targ'ibot ishlarini boshlagan va 33 yoshida xochga mixlangan. Uning shogirdlari (havoriylar) keyinchalik xristianlikni dunyo bo'ylab tarqatdilar.","Xristianlikning muqaddas kitobi — Bibliya (Injil). U ikki qismdan iborat: Eski Ahd (yahudiy Tanaxi bilan asosan mos) va Yangi Ahd (Iso va havoriylar haqidagi yozuvlar). Yangi Ahdda 4 ta Injil (Matto, Mark, Luqo, Yuhanno), Havoriylar amallari, maktublar va Vahiy kitobi bor.","Xristianlikning asosiy aqidalari: Iloh uchligi (Ota, O'g'il, Muqaddas Ruh), Iso payg'ambarning xudo va inson ekanligi, uning xochda jonini fido qilishi orqali insoniyatni gunohdan qutqarganligi, qiyomat va abadiy hayot. Cherkov xizmatlari, suvga cho'mish va boshqa marosimlar diniy hayotning markazidir."]),("Xristianlikning asosiy yo'nalishlari",["Xristianlik tarixiy jihatdan uch asosiy yo'nalishga bo'linadi: pravoslavlik (sharqiy xristianlik — Rossiya, Yunoniston, Serbiya), katolisizm (rim-katolik cherkovi — papa Rim boshchiligida) va protestantlik (Lyuter, Kalvin va boshqalar tomonidan boshlangan islohot natijasi).","1054-yili 'Buyuk bo'linish' (Schism) — pravoslav va katolik cherkovlari ajralib ketdi. Buning sabablari: papaning ustunligi masalasi, Muqaddas Ruhning kelib chiqishi (Filioque), tildagi farqlar (lotin va yunon) va ba'zi marosim farqlari. XVI asrda Reformatsiya natijasida protestantlik paydo bo'ldi.","Xristianlik — dunyodagi eng yirik din: 2,4 milliarddan ortiq tarafdorlari bor (jahon aholisining 31 foizi). Xristianlik G'arb sivilizatsiyasining shakllanishida, san'at, falsafa va ilm-fan rivojida muhim rol o'ynagan. Bayramlari: Rojdestvo (Iso tug'ilgan kun), Pasxa (Iso tirilgan kun) va boshqalar."]),("Yahudiylik va xristianlikning dunyodagi o'rni",["Yahudiylik yirik diaspora dini sifatida butun dunyo bo'ylab tarqalgan: Isroil davlati (1948-yili tashkil topgan), AQSh, Rossiya, Fransiya, Ukraina, Buyuk Britaniya kabi mamlakatlarda yahudiy jamoalari mavjud. Yahudiy madaniyati, ilmi va san'ati jahon sivilizatsiyasiga katta hissa qo'shgan.","Xristianlik Yevropa, Shimoliy va Janubiy Amerika, Avstraliyada hukmron din hisoblanadi, shuningdek Afrika va Osiyoda ham keng tarqalgan. Vatikan davlati — katolik cherkovining markazi va eng kichik mustaqil davlat. Xristian missionerlari dunyo bo'ylab faol ishlaydilar.","O'zbekistonda yahudiy va xristian jamoalari kichik bo'lsa-da, ular faol ishlaydi. Toshkentda pravoslav cherkovlari, katolik cherkovi va sinagoga bor. Davlat barcha dinlarning erkin amal qilishini ta'minlaydi va dinlararo bag'rikenglikni qo'llab-quvvatlaydi. Bu O'zbekiston xalqlarining qadimiy diniy bag'rikenglik an'analarining davomidir."])],})

TOPICS.append({"num":3,"title":"Buddizm va boshqa sharqiy diniy oqimlar","reja":["Buddizm dini va uning paydo bo'lishi.","Buddizmning asosiy ta'limoti.","Hinduizm va uning xususiyatlari.","Konfutsiylik, daosizm va boshqa Sharq oqimlari."],"sections":[("Buddizm dini va uning paydo bo'lishi",["Buddizm — eramizdan avvalgi VI asrda Hindistonda Siddxartha Gautama (Buddha — 'Uyg'ongan') tomonidan asos solingan din va falsafiy ta'limotdir. Buddha shahzoda bo'lib tug'ilgan, lekin 29 yoshida hayotning azob-uqubatlarini ko'rib, dunyoviy hayotdan voz kechib, haqiqatni izlash yo'liga chiqqan.","Buddha 6 yil davomida turli zohid amaliyotlarini bajarib, oxir-oqibat Bodxi daraxti tagida o'tirib, ma'rifatga (uyg'onishga) erishgan. Shundan keyin u 45 yil davomida ta'limotini targ'ib qilgan. Uning ta'limotlari og'zaki an'ana sifatida saqlanib, keyinchalik 'Tripitaka' ('Uch savat') deb nomlangan kitobga jamlangan.","Buddizm hind diniy muhitidan farqli ravishda yagona ilohga emas, balki insonning ichki ma'rifatiga e'tibor qaratadi. U xudoning borligi yoki yo'qligi haqida bahsga kirishmaydi, balki azob-uqubatdan qutulish yo'lini ko'rsatadi. Buddizm Hindiston, Xitoy, Yaponiya, Tibet, Janubi-Sharqiy Osiyo bo'ylab keng tarqalgan."]),("Buddizmning asosiy ta'limoti",["Buddizmning asosiy ta'limoti 'To'rt olijanob haqiqat'dan iborat: 1) hayot azob-uqubatdan iborat (dukkha), 2) azob-uqubatning sababi xohish va ehtiroslar, 3) azob-uqubatdan qutulish mumkin, 4) qutulish yo'li 'Sakkiz olijanob yo'l' orqali.","Sakkiz olijanob yo'l: to'g'ri qarash, to'g'ri niyat, to'g'ri so'z, to'g'ri xulq, to'g'ri yashash, to'g'ri intilish, to'g'ri eslash va to'g'ri jamlanish. Bu yo'lni egallash orqali inson ma'rifatga (nirvanaga) erishadi va azob-uqubat tsiklidan ozod bo'ladi.","Buddizmda muhim tushunchalar: karma (har bir harakat oqibatga olib keladi), reinkarnatsiya (qayta tug'ilish), nirvana (ma'naviy ozodlik holati), sangha (buddistlar jamoasi), bodhisattva (boshqalarni qutqarish uchun nirvanaga kirishni kechiktiruvchi). Buddizm asosan Mahayana, Theravada va Vajrayana yo'nalishlariga bo'linadi."]),("Hinduizm va uning xususiyatlari",["Hinduizm — Hindistonda paydo bo'lgan va dunyoning eng qadimgi dinlaridan biri. Uning aniq asoschisi yo'q — bu turli diniy oqimlar va falsafiy ta'limotlarning birikmasidir. Hinduizm 4 ming yildan ortiq tarixga ega va hozirda 1,2 milliarddan ortiq tarafdorga ega.","Hinduizmning muqaddas matnlari: Vedalar (eng qadimgi — gimnlar va madhiyalar), Upanishadalar (falsafiy matnlar), Mahabharata va Ramayana (epik dostonlar), Bhagavad-gita (eng mashhur ma'naviy matn). Bu matnlar sanskrit tilida yozilgan.","Hinduizmning asosiy xususiyatlari: ko'p xudolarga e'tiqod (asosiylari — Brahma, Vishnu, Shiva), karma va reinkarnatsiya, dharma (axloqiy yo'l), kasta tizimi (4 asosiy kasta: brahmanlar, kshatriyalar, vaishyalar, shudralar), inson hayotining 4 maqsadi (dharma, artha, kama, moksha)."]),("Konfutsiylik, daosizm va boshqa Sharq oqimlari",["Konfutsiylik — Xitoyda eramizdan avvalgi VI-V asrlarda Konfutsiy (Kun-tszi) tomonidan asos solingan ta'limot. U ko'proq axloqiy va ijtimoiy falsafa bo'lib, oilaviy munosabatlar, davlat boshqaruvi va shaxsiy axloqqa e'tibor qaratadi. Asosiy tushunchalar: ren (insonparvarlik), li (rasm-rusum), xiao (ota-onaga itoatkorlik).","Daosizm (taoizm) — Xitoyda Lao Tszi tomonidan asos solingan ta'limot. 'Dao Te Czin' kitobi uning asosiy manbasi. Daosizm tabiat bilan uyg'unlikda yashash, soddalik, harakatsizlik orqali harakat (u-vey) tamoyillarini targ'ib qiladi. Yin va yang — qarama-qarshi kuchlarning uyg'unligi haqidagi tushuncha mashhur.","Boshqa sharq oqimlari: sintoizm (Yaponiya milliy dini — tabiat ruhlariga e'tiqod), sikhizm (Hindistonda XV asrda paydo bo'lgan, Guru Nanak asos solgan), zardushtiylik (qadimgi Eron dini, Zaratushtra asos solgan, otashparastlik). Bularning har biri Sharq sivilizatsiyasiga o'ziga xos hissa qo'shgan."])],})

TOPICS.append({"num":4,"title":"Din va jamiyat","reja":["Dinning ijtimoiy funksiyalari.","Din va madaniyat munosabati.","Din va davlat: dunyoviylik tushunchasi.","Dinning oila va ta'limga ta'siri."],"sections":[("Dinning ijtimoiy funksiyalari",["Din jamiyatda bir qator muhim funksiyalarni bajaradi: dunyoqarash funksiyasi (insonga olamning ma'nosi va o'z o'rni haqida tushuncha beradi), tartibga solish funksiyasi (axloqiy normalar va xulq-atvor qoidalari), birlashtiruvchi funksiya (umumiy e'tiqod orqali jamoa hosil qiladi).","Boshqa muhim funksiyalar: ta'sallo berish (qiyin damlarda ma'naviy quvvat manbai), legitimlashtirish (ijtimoiy tartib va hokimiyatga muqaddas asos berish), kommunikativ (ibodat va marosimlar orqali odamlarni birlashtiradi), madaniy (san'at, adabiyot va me'morchilikni boyitadi).","Din ko'pincha jamoaviy o'zlikni shakllantirishda muhim rol o'ynaydi. Diniy bayramlar, marosimlar va an'analar avloddan-avlodga uzatilib, jamiyatning madaniy yaxlitligini saqlaydi. Diniy qadriyatlar fuqarolarni xayrli ishlarga undaydi va jamiyatda mehr-shafqat muhitini yaratadi."]),("Din va madaniyat munosabati",["Din va madaniyat o'zaro chambarchas bog'liq: din madaniyatning muhim tarkibiy qismi, madaniyat esa diniy g'oyalarning ifoda shaklidir. Dunyodagi eng buyuk san'at asarlari, me'moriy obidalar va adabiy yodgorliklarning aksariyati diniy ilhom bilan yaratilgan.","Diniy madaniyat namunalari: islom me'morchiligida — masjidlar, madrasalar, maqbaralar (Bibi-Xonim, Sherdor, Tillakori); xristian me'morchiligida — soborlar, cherkovlar (Notre-Dame, Vasiliy Blajenniy); buddist me'morchilikda — pagodalar, stupalar; hindu me'morchiligida — me'moriy ibodatxonalar. Har biri o'ziga xos badiiy uslubga ega.","Diniy adabiyot insoniyat ma'naviy merosining muhim qismi: Qur'on, Bibliya, Tora, Vedalar, Tripitaka — bu kitoblar nafaqat diniy, balki adabiy va falsafiy qiymatga ham ega. Sufiy shoirlar (Rumiy, Yassaviy, Navoiy), xristian mistiklari (Toma Kempiyskiy), hind shoirlari diniy mavzuda go'zal asarlar yaratganlar."]),("Din va davlat: dunyoviylik tushunchasi",["Din va davlat munosabatlari turli mamlakatlarda turlicha tashkil etilgan: teokratik davlat (din boshqaruvchi — Vatikan, Eron), davlat dini (rasmiy din — Buyuk Britaniyada anglikanizm, Daniyada lyuteranlik), dunyoviy davlat (din davlatdan ajratilgan — Fransiya, Turkiya, AQSh, O'zbekiston).","Dunyoviylik (sekulyarizm) — davlat va dinning ajratilishi tamoyili. Bu fuqarolarning diniy erkinligini ta'minlaydi, davlat hech bir dinga ustunlik bermaydi va boshqaruvni diniy emas, balki huquqiy asoslarga quradi. Dunyoviylik diniy bag'rikenglikning kafolati hisoblanadi.","O'zbekiston Konstitutsiyasiga ko'ra, mamlakat dunyoviy davlat: din davlatdan, ta'lim dindan ajratilgan. Lekin bu dinga qarshilik degani emas — fuqarolarning diniy erkinligi to'liq kafolatlangan. Davlat barcha dinlarga teng munosabatda bo'ladi va diniy ekstremizmga qarshi qat'iy turadi."]),("Dinning oila va ta'limga ta'siri",["Din ko'pchilik oilalarda muhim rol o'ynaydi: nikoh marosimlari, bola tug'ilishi, ism qo'yish, vafot etganni dafn etish — bularning hammasi diniy an'analar bilan bog'liq. Diniy qadriyatlar oila a'zolari o'rtasidagi munosabatlarni shakllantiradi va axloqiy tarbiya beradi.","Ta'limda din masalasi murakkab: ba'zi mamlakatlarda din dars sifatida o'qitiladi (Germaniya, Italiya), boshqalarida din maktabdan butunlay chiqarilgan (Fransiya, AQSh — davlat maktablarida). O'zbekistonda umumiy ta'lim dunyoviy, lekin maxsus diniy o'quv yurtlari (madrasa, islom universiteti) bor.","Diniy bilim olish fuqaroning huquqi: u o'z dinining asoslarini, tarixini, qadriyatlarini bilishi kerak. Lekin bu bilim majburiy emas, balki ixtiyoriy bo'lishi muhim. Shuningdek, boshqa dinlar haqida ham bilim bag'rikenglik va o'zaro tushunish uchun zarurdir."])],})

TOPICS.append({"num":5,"title":"Dinlararo muloqot va bag'rikenglik","reja":["Diniy bag'rikenglik tushunchasi va uning ahamiyati.","Tarixiy davrlardagi dinlararo munosabatlar.","Zamonaviy dinlararo muloqot va dialog.","O'zbekistonda diniy bag'rikenglik tajribasi."],"sections":[("Diniy bag'rikenglik tushunchasi va uning ahamiyati",["Diniy bag'rikenglik (tolerantlik) — turli dinlar va e'tiqodlar tarafdorlarining bir-birini hurmat qilishi, hamkorlikda yashashi va tinch-totuv munosabatda bo'lishidir. Bu tushuncha diniy erkinlik huquqi bilan chambarchas bog'liq.","Bag'rikenglikning bir necha darajasi bor: passiv bag'rikenglik (boshqa dinlarga aralashmaslik), aktiv bag'rikenglik (boshqa dinlarni hurmat qilish va himoya qilish), dialogik bag'rikenglik (boshqa dinlar bilan muloqot va o'zaro o'rganish). Eng yuqori daraja — dialogik bag'rikenglik bo'lib, u haqiqiy tushunish va hamkorlikni nazarda tutadi.","Bag'rikenglikning ahamiyati: u jamiyatda tinchlik va barqarorlikni ta'minlaydi, fuqarolar o'rtasida do'stlik va hamkorlikka asos yaratadi, har bir kishining ma'naviy erkinligini saqlaydi va madaniy boylikni rivojlantiradi. Bag'rikenglik — sivilizatsiyali jamiyatning muhim belgisidir."]),("Tarixiy davrlardagi dinlararo munosabatlar",["Tarixda dinlararo munosabatlar har xil bo'lgan: ba'zi davrlarda totuvlik va hamkorlik (Ispaniya — Andalus davri, Usmonli imperiyasi), boshqa davrlarda ziddiyatlar va urushlar (xristianlar va musulmonlar o'rtasidagi salib yurishlari, mazhablararo nizolar).","Andalus tajribasi (VIII-XV asrlar Ispaniyada): musulmonlar, xristianlar va yahudiylar bir hududda tinch-totuv yashagan, ilm-fan va madaniyat gullab yashnagan. Cordoba va Granada shaharlari uch dinning hamkorlik markazlariga aylangan. Bu tajriba bag'rikenglikning katta namunasidir.","Ipak yo'li bo'ylab dinlar va madaniyatlar uchrashgan: Buxoro, Samarqand kabi shaharlar islom, xristianlik, buddizm, manixeylik, zardushtiylik tarafdorlari uchun bag'rikeng makonlar bo'lgan. Ulug'beg Samarqandida turli xalqlar va dinlar mutaxassislari birgalikda ishlaganlar."]),("Zamonaviy dinlararo muloqot va dialog",["Zamonaviy dunyoda dinlararo dialog ayniqsa muhim: globallashuv, migratsiya va texnologik rivojlanish turli dinlar tarafdorlarining birgalikda yashashini zaruriyatga aylantirgan. Dinlararo muloqot tinchlik va o'zaro tushunishni ta'minlaydi.","Xalqaro tashkilotlar dinlararo dialogni qo'llab-quvvatlamoqda: BMT, YUNESKO, Yevropa Kengashi maxsus dasturlar yuritmoqda. 'Religions for Peace' (Dinlar tinchlik uchun), 'World Council of Churches' (Cherkovlar Jahon Kengashi) kabi tashkilotlar dinlararo hamkorlikni rivojlantirmoqda.","Dialog uchun zarur shartlar: o'zaro hurmat (boshqa dinni kamsitmaslik), tinglashga tayyor bo'lish (faqat o'z fikrini aytib qolmaslik), umumiy qadriyatlarni topish (mehr-shafqat, adolat, tinchlik), farqlarni qabul qilish (bir-biriga o'xshatishga urinmaslik). Dialog — bahs emas, balki birgalikda haqiqat izlashdir."]),("O'zbekistonda diniy bag'rikenglik tajribasi",["O'zbekiston tarixi davomida ko'p millatli va ko'p dinli mamlakat bo'lib kelgan. Hozirda mamlakatda 16 dan ortiq diniy yo'nalish vakillari yashaydi: musulmonlar (asosiy aholi), pravoslav xristianlar, katoliklar, protestantlar, yahudiylar, buddistlar, hind dinining tarafdorlari va boshqalar.","Mamlakatda dinlararo bag'rikenglikning amaliy ko'rinishlari: turli dinlar muqaddas joylari yonma-yon joylashgan (Toshkentda Hazrati Imom majmuasi yaqinida pravoslav cherkovi, sinagoga); diniy bayramlarda hokimiyat vakillari va boshqa dinlar tarafdorlari bir-birini tabriklaydi; aralash oilalarda turli dinlar tarafdorlari ahil yashaydi.","O'zbekistonning diniy bag'rikenglikdagi tajribasi xalqaro miqyosda yuqori baholanadi. 2017-yili Toshkentda BMT bosh kotibi Antoniyu Guterresh ishtirokida 'Tinchlik, ta'lim va bag'rikenglikni ta'minlash' bo'yicha xalqaro konferensiya bo'lib o'tdi. Imom Termiziy va Imom Buxoriy nomidagi xalqaro markazlar dinlararo bag'rikenglik manbalarini o'rganmoqda."])],})

TOPICS.append({"num":6,"title":"Zamonaviy dunyoda dinning roli","reja":["Zamonaviy davrda dinning o'zgargan o'rni.","Globallashuv va din.","Dinning ijtimoiy va madaniy roli.","Diniy ekstremizm va unga qarshi kurash."],"sections":[("Zamonaviy davrda dinning o'zgargan o'rni",["XX-XXI asrlarda dunyoda din masalasi murakkab tus oldi. Bir tomondan, sekulyarizatsiya jarayoni kuchaydi — ko'plab mamlakatlarda din shaxsiy hayotga ko'chdi va davlat boshqaruvidan ajraldi. Boshqa tomondan, dinga qiziqish yangidan kuchaymoqda — bu 'din qaytishi' deb ataladi.","Zamonaviy davrda din inson hayotida shaxsiy ma'no izlash, ma'naviy ehtiyojlarni qondirish va jamoaga mansublik hissini berish vositasi sifatida ahamiyatini saqlamoqda. Texnologiya rivoji va moddiy farovonlikka qaramay, ko'p odamlar diniy qadriyatlarga muhtojlik sezadi.","Zamonaviy din yangi shakllarda namoyon bo'lmoqda: onlayn ibodatxonalar, raqamli ma'ruzalar va vebinarlar, ijtimoiy tarmoqlardagi diniy targ'ibot, mobil ilovalar (namoz vaqtlari, Qur'on, Bibliya). Pandemiya davrida ko'p diniy marosimlar onlaynda o'tkazildi."]),("Globallashuv va din",["Globallashuv din sohasiga sezilarli ta'sir ko'rsatdi: turli dinlar tarafdorlari bir-biri bilan ko'proq aloqada bo'lmoqda, migratsiya tufayli aralash diniy jamiyatlar shakllanmoqda, axborot tezroq tarqalmoqda. Bu o'zaro tushunish uchun yangi imkoniyatlar va yangi muammolar tug'diradi.","Diniy diaspora — bir mamlakatda yashasa-da, boshqa mamlakat dinining tarafdorlari sifatida o'zlikni saqlovchi guruhlar. Yevropada millionlab musulmon muhojirlari, Yaqin Sharqda xristian jamoalari, AQShda buddistlar va hindular — bularning hammasi globallashuv ta'siri.","Globallashuv ba'zan diniy qarama-qarshilikka olib keladi: turli madaniyatlar to'qnashganda diniy o'zlik haqida tashvishlar paydo bo'ladi. Shu sababli zamonaviy davrda diniy bag'rikenglik, dinlararo dialog va o'zaro hurmat oldingidan ko'ra muhimroqdir."]),("Dinning ijtimoiy va madaniy roli",["Din zamonaviy jamiyatda ham muhim ijtimoiy funksiyalarni bajaradi: xayriya va ijtimoiy yordam (kambag'allarga, kasallarga, qariyalarga g'amxo'rlik), ta'lim (diniy maktablar, universitetlar), tibbiyot (xristian shifoxonalar, islom xayriya tibbiy markazlari), madaniy meros saqlash.","Dinning hozirgi madaniy roli: muqaddas joylarni saqlash va tiklash (Samarqand, Buxoro, Quddus, Vatikan), diniy bayramlar madaniyatning bir qismi sifatida saqlanishi, diniy san'at va musiqa rivoji, diniy tildagi adabiyot. Bu ma'naviy meros millionlab odamlarning hayotiga ma'no beradi.","Din axloqiy ko'rsatma manbai bo'lib qolmoqda: oila qadriyatlari, halollik, mehr-shafqat, adolat, mas'uliyat — bularning hammasi diniy ta'limotlarda mustahkamlangan. Hatto dunyoviy davlatlarda ham qonunlar va ijtimoiy normalar diniy axloqdan ilhom oladi."]),("Diniy ekstremizm va unga qarshi kurash",["Diniy ekstremizm — diniy ta'limotlarni o'ta keskin va buzib talqin qilib, zo'ravonlik va terrorizmga asos sifatida ishlatish. Bu jarayon haqiqiy din bilan hech qanday aloqasi yo'q — barcha jahon dinlari aslida tinchlik va mehr-shafqatga chaqiradi.","Ekstremizm sabablari ko'p qirrali: ijtimoiy-iqtisodiy muammolar (qashshoqlik, ishsizlik), ta'lim yetishmasligi, diniy bilim manbalarining cheklanganligi, tashqi siyosiy ta'sirlar, axborot urushlari va internet orqali tarqaladigan yolg'on g'oyalar. Yoshlar bu ta'sirlarga ko'proq beriluvchan.","Ekstremizmga qarshi kurash usullari: to'g'ri diniy bilim berish (haqiqiy ulamolar va olimlar tomonidan), iqtisodiy va ijtimoiy muammolarni hal qilish, yoshlarni qo'llab-quvvatlash, oilaviy tarbiya, internetdagi zararli kontentni nazoratlash, xalqaro hamkorlik. O'zbekiston bu sohada faol siyosat yuritmoqda — Imom Buxoriy va Imom Termiziy markazlari haqiqiy islom ta'limotini tarqatmoqda."])],})

TOPICS.append({"num":7,"title":"Din va ilm-fan munosabatlari","reja":["Din va ilm-fan: tarixiy munosabatlar.","Buyuk din olimlari va ularning ilmiy hissasi.","Zamonaviy ilm-fan va din muloqoti.","Din va ilmning umumiy va farqli jihatlari."],"sections":[("Din va ilm-fan: tarixiy munosabatlar",["Din va ilm-fan munosabatlari tarixda har xil davrlarni boshdan kechirgan. O'rta asrlarda diniy muassasalar (cherkovlar, madrasalar, monastirlar) ilm-fanning asosiy markazlari bo'lgan. Aksariyat olimlar diniy odamlar — ulamolar, ruhoniylar, monaxlar bo'lgan.","Sharqda islom oltin asri (VIII-XIII asrlar) ilm-fan rivojining yorqin davri bo'lgan. Bu davrda al-Xorazmiy, al-Beruniy, Ibn Sino, al-Forobiy, ar-Roziy kabi olimlar dinga zid emas, balki uni qo'llab-quvvatlovchi ilmiy yutuqlarga erishgan. Ular uchun ilm-fan — Allohni va u yaratgan olamni anglashning vositasi edi.","G'arbda ham ilm-fan rivoji ko'p hollarda diniy muassasalardan boshlangan: birinchi universitetlar (Boloniya, Oksford, Parij) cherkov tomonidan tashkil etilgan. Kopernik, Galiley, Nyuton, Mendel kabi olimlar diniy ekanliklarini ilmiy ish bilan birga olib borganlar."]),("Buyuk din olimlari va ularning ilmiy hissasi",["O'rta Osiyo allomalari ilm-fanning turli sohalarida buyuk yutuqlarga erishganlar: al-Xorazmiy (algebra asoschisi, matematika), al-Beruniy (astronomiya, geografiya), Ibn Sino ('Tib qonunlari', tibbiyot), al-Forobiy (falsafa, mantiq), Mirzo Ulug'beg (astronomiya).","Imom al-Buxoriy (810-870) — eng nufuzli hadis to'plami 'Sahihu-l-Buxoriy' muallifi. U 600 mingdan ortiq hadisni tekshirib, ulardan eng ishonchlilarini saralab olgan. Bu uning ilmiy chuqurligini va metodologik mahoratini ko'rsatadi. Imom Termiziy ham hadis ilmining buyuk olimlaridan.","G'arb diniy olimlari: Tomas Akvinskiy (XIII asr — falsafa va ilohiyot), Nikolay Kuzanskiy (XV asr — falsafa va matematika), Robert Bellarmin (XVI-XVII asrlar — astronomiya), Gregor Mendel (XIX asr — genetika asoschisi, monax). Ularning ishlari ilm va dinning birgalikda rivojlanishini isbotlaydi."]),("Zamonaviy ilm-fan va din muloqoti",["Zamonaviy davrda din va ilm-fan o'rtasida turli munosabatlar mavjud: ziddiyatchi (ular bir-biriga zid), ajratish (ular turli sohalarda ish ko'radi — Stiven Jey Gauld), dialog (o'zaro suhbat va o'rganish), integratsiya (ular bir-birini to'ldiradi — bu eng samarali yondashuv).","Zamonaviy din olimlari va dindor olimlar: Frensis Kollins (genetik, AQSh sog'liqni saqlash milliy institutining sobiq direktori — chuqur dindor xristian), Jon Polkingxorn (kvant fizigi va ilohiyotchi), Mehmet Oz (turk-amerikalik shifokor — musulmon). Ular din va ilm bir-biriga zid emasligini ko'rsatishadi.","Hozir 'din va ilm-fan' ilmiy yo'nalishi mavjud: Templton mukofoti, Vatikan astronomiya rasadxonasi, BioLogos jamiyati va boshqa loyihalar bu munosabatlarni o'rganadi. Tabiat haqidagi ilmiy bilim insonni Yaratuvchi haqida o'ylashga undaydi — bu islom va xristian an'analarida ham bor."]),("Din va ilmning umumiy va farqli jihatlari",["Umumiy jihatlari: ikkalasi ham haqiqatni izlaydi, savol berish va izlanishga undaydi, insoniyatga foyda keltirishga intiladi, ma'lum metodologiya bilan ishlaydi (ilm — empirik usullar, din — vahiy va aql), ma'naviy va intellektual rivojlanishga hissa qo'shadi.","Farqli jihatlari: ilm-fan tabiat hodisalarini empirik usullar bilan o'rganadi (kuzatish, tajriba, o'lchash), uning xulosalari isbotlangan va o'zgarishi mumkin; din asosan ma'naviy haqiqatlarni o'rganadi (hayot ma'nosi, axloq, oxirat), uning manbalari ilohiy vahiy va dindorning shaxsiy tajribasi.","Ilm 'qanday?' degan savolga javob beradi (mexanizmlar, jarayonlar, sabab-oqibat), din 'nima uchun?' degan savolga javob beradi (maqsad, ma'no, qadriyat). Ikkalasi ham insonning to'liq tushunishi uchun zarurdir. Quyoshning fizik tabiatini ilm o'rganadi, lekin uning yaratilish maqsadi va inson uchun ahamiyati haqida din o'ylantiradi."])],})

TOPICS.append({"num":8,"title":"Korrupsiyaga qarshi kurashning jahon tajribasi","reja":["Korrupsiya tushunchasi va uning oqibatlari.","Korrupsiyaga qarshi kurashning jahon tajribasi.","Xalqaro tashkilotlar va konvensiyalar.","O'zbekistonda korrupsiyaga qarshi kurash."],"sections":[("Korrupsiya tushunchasi va uning oqibatlari",["Korrupsiya — bu mansabdor shaxsning o'z mansab vakolatlarini shaxsiy yoki guruhiy manfaatlar yo'lida suiiste'mol qilishidir. Lotincha 'corruptio' so'zidan kelib chiqqan bo'lib, 'buzilish, sotib olish' degan ma'noni anglatadi. Korrupsiya — har bir jamiyat va davlat uchun jiddiy tahdid.","Korrupsiyaning shakllari: pora olish va berish, mansab vakolatlarini suiiste'mol qilish, davlat mulkini o'zlashtirish, qarindosh-urug'chilik (nepotizm), do'stchilikka asoslangan tayinlash (kronizm), tijoratlashtirilgan rishvat (kickback), aldash va firibgarlik. Har biri jamiyatga zarar yetkazadi.","Korrupsiyaning oqibatlari: iqtisodiy o'sishni susaytiradi, davlat byudjetiga zarar keltiradi, ijtimoiy adolatsizlikni kuchaytiradi, fuqarolar ishonchini yo'qotadi, xorijiy investitsiyalarni cheklaydi, kambag'allikni chuqurlashtiradi, demokratik institutlarni zaiflashtiradi va xalqaro obro'ga zarar yetkazadi."]),("Korrupsiyaga qarshi kurashning jahon tajribasi",["Singapur tajribasi — eng muvaffaqiyatli misollardan biri. Li Kuan Yu rahbarligida (1959-1990) mamlakat dunyoning eng korrupsiyalashgan davlatlaridan biridan eng halol davlatlardan biriga aylangan. Asosiy choralar: yuqori ish haqi, mustaqil korrupsiyaga qarshi qo'mita (CPIB), qattiq jazo, shaffof boshqaruv.","Gonkong tajribasi: 1974-yili Mustaqil Korrupsiyaga Qarshi Komissiya (ICAC) tashkil etilgan. U uchta yo'nalishda ishlaydi: jinoiy ta'qib (huquqbuzarlarni qo'lga olish), oldini olish (tizimli choralar) va ta'lim (jamoatchilik bilan ishlash). Bu kompleks yondashuv juda samarali.","Skandinaviya mamlakatlari (Daniya, Norvegiya, Finlyandiya, Shvetsiya) doimo eng kam korrupsiyali davlatlar ro'yxatida. Ularning sirlari: yuqori shaffoflik (hukumat hujjatlari ochiq), ozod OAV, mustaqil sud tizimi, fuqarolar faolligi va past tolerantlik. Boshqa muvaffaqiyatli tajribalar: Yangi Zelandiya, Janubiy Koreya, Jorjiya."]),("Xalqaro tashkilotlar va konvensiyalar",["BMTning Korrupsiyaga qarshi konvensiyasi (UNCAC) — 2003-yili qabul qilingan, korrupsiyaga qarshi kurash bo'yicha eng keng qamrovli xalqaro hujjat. 190 dan ortiq mamlakat ratifikatsiya qilgan, jumladan O'zbekiston ham. U preventiv choralar, jinoiylashtirish, xalqaro hamkorlik va aktivlarni qaytarib olish masalalarini qamrab oladi.","Boshqa muhim xalqaro tashkilotlar: Transparency International (Korrupsiya idroki indeksini har yili nashr etadi), GRECO (Yevropa Kengashining korrupsiyaga qarshi davlatlar guruhi), OECD korrupsiyaga qarshi konvensiyasi, FATF (moliyaviy harakatlar bo'yicha ishchi guruh — pul yuvishga qarshi).","Xalqaro hamkorlik mexanizmlari: jinoyatchilarni ekstradisiya qilish, o'g'irlangan aktivlarni qaytarish, axborot almashish, birgalikdagi tergov, banklar orasidagi shaffoflik (CRS — umumiy hisobot standarti). Bu mexanizmlar transmilliy korrupsiyaga qarshi samarali kurashish imkonini beradi."]),("O'zbekistonda korrupsiyaga qarshi kurash",["O'zbekistonda korrupsiyaga qarshi kurash davlat siyosatining ustuvor yo'nalishlaridan biriga aylantirilgan. 2017-yili 'Korrupsiyaga qarshi kurashish to'g'risida'gi qonun qabul qilindi. 2020-yili Korrupsiyaga qarshi kurashish agentligi tashkil etildi — u to'g'ridan-to'g'ri Prezidentga bo'ysunadi.","Amalga oshirilgan choralar: davlat xizmatchilarining daromadlari va mulkini deklaratsiya qilish, davlat xaridlarini elektron tizimga o'tkazish, davlat xizmatlarini onlayn shaklga aylantirish (kamroq inson aralashuvi), shaffoflik va hisobdorlikni oshirish, xabar beruvchilarni himoyalash, korrupsiyaga qarshi ta'lim joriy etish.","Natijalar: Transparency International ning korrupsiya idroki indeksida O'zbekiston pozitsiyasi sezilarli yaxshilandi (2013-yilda 168-o'rin, 2023-yilda — 121-o'rin). Lekin hali ko'p ishlar qilinishi kerak. Korrupsiyaga qarshi kurash davom etmoqda — muvaffaqiyatlik fuqarolar, davlat va biznesning birgalikdagi sa'y-harakatlariga bog'liq."])],})

